{"content":"{
  "compilerOptions": {
    "lib": ["dom", "dom.iterable", "esnext"],
    "allowJs": true,
    "skipLibCheck": true,
    "strict": true,
    "noEmit": true,
    "esModuleInterop": true,
    "module": "esnext",
    "moduleResolution": "bundler",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "jsx": "preserve",
    "incremental": true,
    "plugins": [
      {
        "name": "next"
      }
    ],
    "paths": {
      "@/*": ["./*"]
    }
  },
  "include": ["next-env.d.ts", "**/*.ts", "**/*.tsx", ".next/types/**/*.ts"],
  "exclude": ["node_modules", "vite.config.ts"]
}"}

{"content":"'use client';
import React, { useState } from 'react';
import { User } from '../types';
import {
  User as UserIcon, Mail, Bell, Shield, Key, Trash2, Copy, Eye, EyeOff,
  CreditCard, Check, Download, Star, Zap, Briefcase, ArrowRight, Loader2,
  Crown, Rocket, BarChart3, AlertTriangle, ChevronRight, ExternalLink,
  Lock, FileText, Calendar, RefreshCw, Settings, LogOut
} from 'lucide-react';

// --- TYPES ---
interface AccountProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: string) => void;
  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
  monthlyProjectCount: number;
  maxProjects: number;
  initialTab?: 'profile' | 'subscription' | 'billing' | 'api';
}

// --- PLAN DATA ---
const PLAN_DATA = {
  free: {
    name: 'Starter',
    price: 'Gratuit',
    priceNum: 0,
    icon: <Zap size={20} />,
    color: 'gray',
    maxProjects: 1,
    features: [
      '1 Projet (Site Web)',
      'Monitoring Mensuel',
      '20 Prompts Standards',
      'Score Visibilité IA',
      'Support Email Standard',
    ],
  },
  pro: {
    name: 'Pro',
    price: '89€/mois',
    priceNum: 89,
    icon: <Rocket size={20} />,
    color: 'emerald',
    maxProjects: 3,
    features: [
      '3 Projets simultanés',
      'Monitoring Hebdomadaire',
      'Exports PDF & CSV',
      'Moteur de Recommandations',
      'Générateur Packs Contenu',
      'Support Prioritaire',
    ],
  },
  enterprise: {
    name: 'Agency',
    price: 'Sur devis',
    priceNum: -1,
    icon: <Briefcase size={20} />,
    color: 'violet',
    maxProjects: Infinity,
    features: [
      'Projets illimités',
      'Monitoring Quotidien',
      'Rapports Marque Blanche',
      'Accès API Full',
      'Opérations Bulk (Prompts)',
      'Account Manager Dédié',
    ],
  },
};

type TabId = 'profile' | 'subscription' | 'billing' | 'api';

const TABS: { id: TabId; label: string; icon: React.ReactNode }[] = [
  { id: 'profile', label: 'Profil', icon: <UserIcon size={18} /> },
  { id: 'subscription', label: 'Abonnement', icon: <Crown size={18} /> },
  { id: 'billing', label: 'Facturation', icon: <CreditCard size={18} /> },
  { id: 'api', label: 'API & Sécurité', icon: <Shield size={18} /> },
];

// --- MOCK INVOICES ---
const MOCK_INVOICES = [
  { id: 'INV-2024-006', date: '2024-06-01', amount: '89,00 €', status: 'paid' as const },
  { id: 'INV-2024-005', date: '2024-05-01', amount: '89,00 €', status: 'paid' as const },
  { id: 'INV-2024-004', date: '2024-04-01', amount: '89,00 €', status: 'paid' as const },
];

// --- MAIN COMPONENT ---
const Account: React.FC<AccountProps> = ({
  user,
  onLogout,
  onNavigate,
  onUpgrade,
  monthlyProjectCount,
  maxProjects,
  initialTab = 'profile',
}) => {
  const [activeTab, setActiveTab] = useState<TabId>(initialTab);
  const [isLoading, setIsLoading] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const [notifications, setNotifications] = useState({
    email: true,
    reports: true,
    marketing: false,
    alerts: true,
  });

  const currentPlan = PLAN_DATA[user?.plan || 'free'];
  const projectUsagePercent = maxProjects === Infinity ? 10 : Math.min((monthlyProjectCount / maxProjects) * 100, 100);
  const isNearLimit = maxProjects !== Infinity && monthlyProjectCount >= maxProjects * 0.8;
  const mockApiKey = 'cb_live_sk_7f3a9b2c4d5e6f7890abcdef12345678';

  // --- HANDLERS ---
  const handleSubscribePro = async () => {
    if (!user || !user.workspaceId) {
      alert('Erreur: ID de workspace manquant. Veuillez vous reconnecter.');
      return;
    }
    setIsLoading(true);
    try {
      const res = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ workspaceId: user.workspaceId, plan: 'pro' }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Erreur lors de la création de la session');
      if (data.url) window.location.href = data.url;
    } catch (error) {
      console.error('Payment error:', error);
      alert("Erreur lors de l'initialisation du paiement.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleManageSubscription = async () => {
    if (!user || !user.workspaceId) return;
    setIsLoading(true);
    try {
      const res = await fetch('/api/stripe/portal', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ workspaceId: user.workspaceId }),
      });
      const data = await res.json();
      if (data.url) {
        window.location.href = data.url;
      } else {
        alert(data.error || "Impossible d'accéder au portail.");
      }
    } catch (error) {
      console.error(error);
      alert("Erreur d'accès au portail de facturation.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleContactSales = () => {
    window.location.href =
      'mailto:sales@citedby.ai?subject=Demande%20Plan%20Agency%20Multi-Clients&body=Bonjour,%20je%20suis%20une%20agence%20et%20je%20souhaite%20gérer%20plusieurs%20projets.';
  };

  const copyApiKey = () => {
    navigator.clipboard.writeText(mockApiKey);
  };

  const getNextPlan = (): 'pro' | 'enterprise' | null => {
    if (user?.plan === 'free') return 'pro';
    if (user?.plan === 'pro') return 'enterprise';
    return null;
  };

  // --- SUB-RENDERS ---

  const renderProfileTab = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-left-4 duration-300">
      {/* Personal Info Card */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
        <div className="absolute top-0 right-0 w-40 h-40 bg-primary/5 blur-3xl rounded-full -z-10" />
        <div className="p-6 border-b border-white/5">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
              <UserIcon size={16} className="text-primary" />
            </div>
            Informations personnelles
          </h3>
        </div>
        <div className="p-6 space-y-5">
          <div className="grid md:grid-cols-2 gap-5">
            <div className="space-y-1.5">
              <label className="text-xs font-medium text-gray-500 uppercase tracking-wide">Nom complet</label>
              <div className="bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white">
                {user?.name || 'Non renseigné'}
              </div>
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-medium text-gray-500 uppercase tracking-wide">Email</label>
              <div className="bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white flex items-center gap-2">
                <Mail size={14} className="text-gray-500" />
                {user?.email || 'Non renseigné'}
              </div>
            </div>
          </div>
          <div className="grid md:grid-cols-2 gap-5">
            <div className="space-y-1.5">
              <label className="text-xs font-medium text-gray-500 uppercase tracking-wide">Rôle</label>
              <div className="bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white capitalize">
                {user?.role || 'owner'}
              </div>
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-medium text-gray-500 uppercase tracking-wide">ID Utilisateur</label>
              <div className="bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-gray-500 font-mono text-sm">
                {user?.id || 'N/A'}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Notification Preferences */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
        <div className="p-6 border-b border-white/5">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-blue-500/10 flex items-center justify-center">
              <Bell size={16} className="text-blue-400" />
            </div>
            Notifications
          </h3>
        </div>
        <div className="p-6 space-y-4">
          {[
            { key: 'email' as const, label: 'Notifications par email', desc: 'Recevez les mises à jour importantes par email' },
            { key: 'reports' as const, label: 'Rapports hebdomadaires', desc: 'Résumé de performance envoyé chaque lundi' },
            { key: 'alerts' as const, label: 'Alertes de score', desc: 'Notification quand votre score change significativement' },
            { key: 'marketing' as const, label: 'Actualités & conseils', desc: 'Tips AEO et nouvelles fonctionnalités' },
          ].map((item) => (
            <div key={item.key} className="flex items-center justify-between py-3 border-b border-white/5 last:border-0">
              <div>
                <p className="text-sm font-medium text-white">{item.label}</p>
                <p className="text-xs text-gray-500 mt-0.5">{item.desc}</p>
              </div>
              <button
                onClick={() => setNotifications((prev) => ({ ...prev, [item.key]: !prev[item.key] }))}
                className={`relative w-11 h-6 rounded-full transition-all duration-300 ${
                  notifications[item.key] ? 'bg-primary' : 'bg-white/10'
                }`}
              >
                <div
                  className={`absolute top-0.5 w-5 h-5 rounded-full bg-white shadow-sm transition-all duration-300 ${
                    notifications[item.key] ? 'left-[22px]' : 'left-0.5'
                  }`}
                />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const renderSubscriptionTab = () => {
    const nextPlan = getNextPlan();
    const nextPlanData = nextPlan ? PLAN_DATA[nextPlan] : null;

    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-left-4 duration-300">
        {/* Current Plan Card */}
        <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
          <div className="absolute top-0 right-0 w-60 h-60 bg-primary/5 blur-3xl rounded-full -z-10" />
          <div className="absolute bottom-0 left-0 w-40 h-40 bg-blue-500/5 blur-3xl rounded-full -z-10" />

          <div className="p-6 border-b border-white/5 flex items-center justify-between">
            <h3 className="text-lg font-semibold text-white flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
                <Crown size={16} className="text-primary" />
              </div>
              Mon abonnement
            </h3>
            <span className="text-xs text-gray-500 font-mono">ID: {user?.id || 'GUEST'}</span>
          </div>

          <div className="p-6">
            {/* Plan Header */}
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-primary to-emerald-800 flex items-center justify-center text-white shadow-lg shadow-primary/20">
                  {currentPlan.icon}
                </div>
                <div>
                  <h4 className="text-xl font-bold text-white">Plan {currentPlan.name}</h4>
                  <div className="flex items-center gap-2 mt-1">
                    <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                    <span className="text-xs text-emerald-400 font-medium uppercase tracking-wide">Actif</span>
                    {user?.plan !== 'free' && (
                      <span className="text-xs text-gray-500 ml-2">{currentPlan.price}</span>
                    )}
                  </div>
                </div>
              </div>
              {nextPlan && (
                <button
                  onClick={() => setActiveTab('subscription')}
                  className="text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-4 py-2 rounded-lg transition-colors text-gray-300"
                >
                  Changer d'offre
                </button>
              )}
            </div>

            {/* Project Counter */}
            <div className="mb-6 bg-black/20 p-5 rounded-xl border border-white/5 space-y-4">
              <div>
                <div className="flex justify-between items-end mb-2">
                  <span className="text-sm text-gray-400 flex items-center gap-2">
                    <BarChart3 size={14} />
                    Projets ce mois
                  </span>
                  <span className="text-sm font-bold text-white">
                    {maxProjects === Infinity
                      ? `${monthlyProjectCount} / ∞`
                      : `${monthlyProjectCount} / ${maxProjects}`}
                  </span>
                </div>
                <div className="h-3 bg-gray-800 rounded-full overflow-hidden">
                  <div
                    className={`h-full rounded-full transition-all duration-700 ${
                      isNearLimit
                        ? 'bg-gradient-to-r from-amber-500 to-red-500'
                        : 'bg-gradient-to-r from-primary to-emerald-400'
                    }`}
                    style={{ width: `${projectUsagePercent}%` }}
                  />
                </div>
                {isNearLimit && (
                  <p className="text-xs text-amber-400 mt-2 flex items-center gap-1">
                    <AlertTriangle size={12} />
                    Vous approchez de votre limite de projets
                  </p>
                )}
              </div>

              <div>
                <div className="flex justify-between items-end mb-2">
                  <span className="text-sm text-gray-400">Crédits de Génération</span>
                  <span className="text-sm font-bold text-white">{user?.credits ?? 0} restants</span>
                </div>
                <div className="h-3 bg-gray-800 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-gradient-to-r from-blue-500 to-cyan-400 rounded-full transition-all duration-500"
                    style={{ width: `${Math.min(((user?.credits || 0) / 100) * 100, 100)}%` }}
                  />
                </div>
              </div>

              <p className="text-xs text-gray-500 flex items-center gap-1 pt-1">
                <Star size={10} className="text-amber-400" /> Renouvellement des quotas le 01 du mois prochain
              </p>
            </div>

            {/* Features */}
            <div className="space-y-3">
              <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">
                Fonctionnalités activées
              </p>
              {currentPlan.features.map((feat, i) => (
                <div key={i} className="flex items-center gap-3 text-sm text-gray-300">
                  <div className="w-5 h-5 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                    <Check size={12} className="text-primary" />
                  </div>
                  {feat}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Upgrade CTA */}
        {nextPlan && nextPlanData && (
          <div className="relative overflow-hidden rounded-2xl border border-primary/30 bg-gradient-to-br from-primary/5 via-transparent to-blue-500/5">
            <div className="absolute top-0 right-0 w-80 h-80 bg-primary/10 blur-[100px] rounded-full -z-10" />

            <div className="p-6">
              <div className="flex items-start justify-between mb-6">
                <div>
                  <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 border border-primary/20 text-primary text-xs font-bold uppercase tracking-wider mb-4">
                    <Rocket size={12} />
                    Upgrade recommandé
                  </div>
                  <h3 className="text-2xl font-bold text-white mb-2">
                    Passez au {nextPlanData.name}
                  </h3>
                  <p className="text-gray-400 text-sm max-w-md">
                    {nextPlan === 'pro'
                      ? 'Débloquez 3 projets, le monitoring hebdomadaire et les exports pour accélérer votre croissance AEO.'
                      : 'Gestion multi-clients illimitée, rapports marque blanche et account manager dédié.'}
                  </p>
                </div>
                {nextPlan === 'pro' && (
                  <div className="text-right">
                    <div className="text-3xl font-bold text-white">89€</div>
                    <div className="text-sm text-gray-500">/mois</div>
                  </div>
                )}
              </div>

              {/* Comparison Grid */}
              <div className="grid md:grid-cols-2 gap-4 mb-6">
                <div className="bg-white/5 rounded-xl p-4 border border-white/5">
                  <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">
                    Votre plan actuel
                  </p>
                  <ul className="space-y-2">
                    {currentPlan.features.slice(0, 4).map((f, i) => (
                      <li key={i} className="text-sm text-gray-500 flex items-center gap-2">
                        <Check size={14} className="text-gray-600" />
                        {f}
                      </li>
                    ))}
                  </ul>
                </div>
                <div className="bg-primary/5 rounded-xl p-4 border border-primary/20">
                  <p className="text-[10px] font-bold text-primary uppercase tracking-widest mb-3">
                    Plan {nextPlanData.name}
                  </p>
                  <ul className="space-y-2">
                    {nextPlanData.features.slice(0, 4).map((f, i) => (
                      <li key={i} className="text-sm text-white flex items-center gap-2">
                        <Check size={14} className="text-primary" />
                        <span className="font-medium">{f}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>

              <div className="flex gap-3">
                {nextPlan === 'pro' ? (
                  <button
                    onClick={handleSubscribePro}
                    disabled={isLoading}
                    className="flex-1 py-3.5 bg-primary text-black font-bold rounded-xl hover:brightness-110 transition-all flex items-center justify-center gap-2 shadow-lg shadow-primary/20"
                  >
                    {isLoading ? (
                      <Loader2 size={18} className="animate-spin" />
                    ) : (
                      <>
                        <Rocket size={18} /> Passer au Pro
                      </>
                    )}
                  </button>
                ) : (
                  <button
                    onClick={handleContactSales}
                    className="flex-1 py-3.5 bg-white text-black font-bold rounded-xl hover:bg-gray-100 transition-all flex items-center justify-center gap-2"
                  >
                    <Briefcase size={18} /> Contacter l'équipe
                  </button>
                )}
              </div>
            </div>
          </div>
        )}

        {/* All Plans Comparison */}
        <div>
          <h3 className="text-lg font-semibold text-white mb-4">Comparer les offres</h3>
          <div className="grid md:grid-cols-3 gap-4">
            {(['free', 'pro', 'enterprise'] as const).map((planKey) => {
              const plan = PLAN_DATA[planKey];
              const isCurrent = user?.plan === planKey;
              return (
                <div
                  key={planKey}
                  className={`rounded-2xl border p-5 transition-all ${
                    isCurrent
                      ? 'border-primary/50 bg-primary/5 shadow-[0_0_30px_rgba(16,185,129,0.08)]'
                      : 'border-white/10 bg-white/[0.02] hover:border-white/20'
                  }`}
                >
                  {isCurrent && (
                    <div className="text-[10px] font-bold text-primary uppercase tracking-widest mb-3 flex items-center gap-1">
                      <Check size={10} /> Plan actuel
                    </div>
                  )}
                  <div className="flex items-center gap-2 mb-2">
                    <span className={isCurrent ? 'text-primary' : 'text-gray-400'}>{plan.icon}</span>
                    <h4 className="font-bold text-white">{plan.name}</h4>
                  </div>
                  <div className="text-2xl font-bold text-white mb-4 font-serif">
                    {plan.price === 'Gratuit' ? 'Gratuit' : plan.price === 'Sur devis' ? 'Sur devis' : plan.price}
                  </div>
                  <ul className="space-y-2 mb-5">
                    {plan.features.slice(0, 4).map((f, i) => (
                      <li key={i} className="text-xs text-gray-400 flex items-center gap-2">
                        <Check size={12} className={isCurrent ? 'text-primary' : 'text-gray-600'} />
                        {f}
                      </li>
                    ))}
                  </ul>
                  {isCurrent ? (
                    <div className="text-center py-2 text-xs text-primary font-medium">Actif</div>
                  ) : planKey === 'pro' ? (
                    <button
                      onClick={handleSubscribePro}
                      disabled={isLoading}
                      className="w-full py-2.5 bg-primary text-black font-bold rounded-lg text-sm hover:brightness-110 transition-all flex items-center justify-center gap-1"
                    >
                      {isLoading ? <Loader2 size={14} className="animate-spin" /> : 'Passer au Pro'}
                    </button>
                  ) : planKey === 'enterprise' ? (
                    <button
                      onClick={handleContactSales}
                      className="w-full py-2.5 bg-white text-black font-bold rounded-lg text-sm hover:bg-gray-100 transition-all"
                    >
                      Contacter
                    </button>
                  ) : (
                    <div className="text-center py-2 text-xs text-gray-600">Plan de base</div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    );
  };

  const renderBillingTab = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-left-4 duration-300">
      {/* Payment Method */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
        <div className="p-6 border-b border-white/5">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-blue-500/10 flex items-center justify-center">
              <CreditCard size={16} className="text-blue-400" />
            </div>
            Méthode de paiement
          </h3>
        </div>
        <div className="p-6 space-y-5">
          <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
            <span className="text-gray-400">Prochaine facture</span>
            <span className="font-medium text-white text-lg">
              {user?.plan === 'free' ? '-' : '01/07/2024'}
            </span>
          </div>
          <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
            <span className="text-gray-400">Montant mensuel</span>
            <span className="font-medium text-white">
              {user?.plan === 'free' ? 'Gratuit' : currentPlan.price}
            </span>
          </div>
          <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
            <span className="text-gray-400">Statut Stripe</span>
            <span className="text-xs text-gray-500 italic flex items-center gap-1">
              <ExternalLink size={10} /> Via Portail
            </span>
          </div>
          <button
            onClick={handleManageSubscription}
            disabled={isLoading}
            className="w-full py-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-sm text-gray-300 hover:text-white flex items-center justify-center gap-2 transition-all group"
          >
            {isLoading ? (
              <Loader2 size={16} className="animate-spin" />
            ) : (
              <CreditCard size={16} className="group-hover:text-primary transition-colors" />
            )}
            Gérer via Stripe
          </button>
        </div>
      </div>

      {/* Invoice History */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
        <div className="p-6 border-b border-white/5">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-amber-500/10 flex items-center justify-center">
              <FileText size={16} className="text-amber-400" />
            </div>
            Historique des factures
          </h3>
        </div>
        <div className="divide-y divide-white/5">
          {user?.plan === 'free' ? (
            <div className="p-8 text-center text-gray-500">
              <FileText size={40} className="mx-auto mb-3 opacity-20" />
              <p className="text-sm">Aucune facture — plan gratuit actif</p>
            </div>
          ) : (
            MOCK_INVOICES.map((inv) => (
              <div key={inv.id} className="px-6 py-4 flex items-center justify-between hover:bg-white/[0.02] transition-colors">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-lg bg-white/5 flex items-center justify-center">
                    <FileText size={16} className="text-gray-400" />
                  </div>
                  <div>
                    <p className="text-sm font-medium text-white">{inv.id}</p>
                    <p className="text-xs text-gray-500 flex items-center gap-1">
                      <Calendar size={10} /> {inv.date}
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <span className="text-sm font-medium text-white">{inv.amount}</span>
                  <span className="text-[10px] font-bold uppercase tracking-wider px-2 py-1 rounded-full bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">
                    Payé
                  </span>
                  <button className="p-2 hover:bg-white/5 rounded-lg transition-colors text-gray-400 hover:text-white">
                    <Download size={14} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );

  const renderApiTab = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-left-4 duration-300">
      {/* API Key */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
        <div className="p-6 border-b border-white/5">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-violet-500/10 flex items-center justify-center">
              <Key size={16} className="text-violet-400" />
            </div>
            Clé API
          </h3>
        </div>
        <div className="p-6 space-y-4">
          <p className="text-sm text-gray-400">
            Utilisez cette clé pour accéder à l'API CitedBy depuis vos applications.
          </p>
          <div className="flex items-center gap-2">
            <div className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 font-mono text-sm text-gray-300 overflow-hidden">
              {showApiKey ? mockApiKey : '••••••••••••••••••••••••••••••••••••'}
            </div>
            <button
              onClick={() => setShowApiKey(!showApiKey)}
              className="p-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl transition-colors text-gray-400 hover:text-white"
            >
              {showApiKey ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
            <button
              onClick={copyApiKey}
              className="p-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl transition-colors text-gray-400 hover:text-white"
            >
              <Copy size={16} />
            </button>
          </div>
          <div className="flex items-center gap-2 text-xs text-gray-500">
            <RefreshCw size={10} />
            <span>Dernière rotation : 01/01/2024</span>
          </div>
          <button className="text-xs text-primary hover:text-white transition-colors flex items-center gap-1">
            <RefreshCw size={12} /> Régénérer la clé
          </button>
        </div>
      </div>

      {/* Security */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03]">
        <div className="p-6 border-b border-white/5">
          <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
              <Lock size={16} className="text-primary" />
            </div>
            Sécurité
          </h3>
        </div>
        <div className="p-6 space-y-4">
          <div className="flex items-center justify-between py-3 border-b border-white/5">
            <div>
              <p className="text-sm font-medium text-white">Authentification à deux facteurs</p>
              <p className="text-xs text-gray-500 mt-0.5">Ajoutez une couche de sécurité supplémentaire</p>
            </div>
            <button className="text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-4 py-2 rounded-lg transition-colors text-gray-300">
              Configurer
            </button>
          </div>
          <div className="flex items-center justify-between py-3 border-b border-white/5">
            <div>
              <p className="text-sm font-medium text-white">Sessions actives</p>
              <p className="text-xs text-gray-500 mt-0.5">1 session active sur cet appareil</p>
            </div>
            <button className="text-xs text-red-400 hover:text-red-300 transition-colors">
              Tout déconnecter
            </button>
          </div>
        </div>
      </div>

      {/* Danger Zone */}
      <div className="relative overflow-hidden rounded-2xl border border-red-500/20 bg-red-500/[0.02]">
        <div className="p-6 border-b border-red-500/10">
          <h3 className="text-lg font-semibold text-red-400 flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-red-500/10 flex items-center justify-center">
              <AlertTriangle size={16} className="text-red-400" />
            </div>
            Zone de danger
          </h3>
        </div>
        <div className="p-6 space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-white">Supprimer mon compte</p>
              <p className="text-xs text-gray-500 mt-0.5">
                Cette action est irréversible. Toutes vos données seront supprimées.
              </p>
            </div>
            <button className="text-xs bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 px-4 py-2 rounded-lg transition-colors text-red-400 flex items-center gap-1.5">
              <Trash2 size={12} /> Supprimer
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // --- MAIN RENDER ---
  return (
    <div className="max-w-5xl mx-auto px-4 py-8 relative animate-in fade-in duration-500">
      {/* Unified Header */}
      <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-white/[0.03] mb-8">
        {/* Background decorations */}
        <div className="absolute top-0 right-0 w-80 h-80 bg-primary/5 blur-[100px] rounded-full -z-10" />
        <div className="absolute bottom-0 left-0 w-60 h-60 bg-blue-500/5 blur-[80px] rounded-full -z-10" />

        <div className="p-6 md:p-8">
          <div className="flex flex-col md:flex-row items-start md:items-center gap-6">
            {/* Avatar */}
            <div className="relative">
              <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-primary to-emerald-800 flex items-center justify-center text-white text-3xl font-bold shadow-lg shadow-primary/20">
                {user?.name?.[0]?.toUpperCase() || user?.email?.[0]?.toUpperCase() || 'U'}
              </div>
              <div className="absolute -bottom-1 -right-1 w-6 h-6 rounded-full bg-emerald-500 border-2 border-[#0a0a0f] flex items-center justify-center">
                <Check size={10} className="text-white" />
              </div>
            </div>

            {/* User Info */}
            <div className="flex-1">
              <div className="flex items-center gap-3 mb-1">
                <h1 className="text-2xl font-bold text-white">{user?.name || 'Utilisateur'}</h1>
                <span
                  className={`text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full border ${
                    user?.plan === 'enterprise'
                      ? 'bg-violet-500/10 text-violet-400 border-violet-500/20'
                      : user?.plan === 'pro'
                      ? 'bg-primary/10 text-primary border-primary/20'
                      : 'bg-white/5 text-gray-400 border-white/10'
                  }`}
                >
                  {currentPlan.name}
                </span>
              </div>
              <p className="text-sm text-gray-500">{user?.email}</p>
            </div>

            {/* Credits Badge */}
            <div className="md:text-right">
              <div className="inline-flex items-center gap-3 bg-white/5 border border-white/10 rounded-xl px-5 py-3">
                <div>
                  <p className="text-[10px] text-gray-500 uppercase tracking-wide">Crédits</p>
                  <p className="text-lg font-bold text-white">{user?.credits ?? 0}</p>
                </div>
                <div className="w-px h-8 bg-white/10" />
                <button className="text-xs text-primary hover:text-white transition-colors font-medium flex items-center gap-1">
                  <Zap size={12} /> Recharger
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="mb-8">
        <div className="inline-flex bg-white/5 p-1.5 rounded-2xl border border-white/10 w-full md:w-auto">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex-1 md:flex-initial px-5 py-2.5 rounded-xl text-sm font-medium transition-all duration-300 flex items-center justify-center gap-2 ${
                activeTab === tab.id
                  ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.2)] font-bold'
                  : 'text-gray-400 hover:text-white hover:bg-white/5'
              }`}
            >
              <span className={activeTab === tab.id ? '' : 'opacity-50'}>{tab.icon}</span>
              <span className="hidden md:inline">{tab.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Tab Content */}
      <div>
        {activeTab === 'profile' && renderProfileTab()}
        {activeTab === 'subscription' && renderSubscriptionTab()}
        {activeTab === 'billing' && renderBillingTab()}
        {activeTab === 'api' && renderApiTab()}
      </div>
    </div>
  );
};

export default Account;
"}

{"content":"import React, { useState } from 'react';
import { User } from '../types';
import { Zap, CreditCard, Check, Download, Star, ArrowLeft, LayoutList, ShieldCheck, Briefcase, Globe, Server, ArrowRight, Loader2 } from 'lucide-react';

interface PlanProps {
  onBack: () => void;
  onNavigateToProjects: () => void;
  user: User | null;
}

const Plan: React.FC<PlanProps> = ({ onBack, onNavigateToProjects, user }) => {
  const [activeTab, setActiveTab] = useState<'my-plan' | 'pricing'>('my-plan');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubscribePro = async () => {
    if (!user || !user.workspaceId) {
        alert("Erreur: ID de workspace manquant. Veuillez vous reconnecter.");
        return;
    }

    setIsLoading(true);
    try {
        const res = await fetch('/api/stripe/checkout', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                workspaceId: user.workspaceId, 
                plan: 'pro' 
            })
        });

        const data = await res.json();

        if (!res.ok) throw new Error(data.error || 'Erreur lors de la création de la session');

        if (data.url) {
            window.location.href = data.url;
        }
    } catch (error) {
        console.error("Payment error:", error);
        alert("Erreur lors de l'initialisation du paiement.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleManageSubscription = async () => {
    if (!user || !user.workspaceId) return;

    setIsLoading(true);
    try {
        const res = await fetch('/api/stripe/portal', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ workspaceId: user.workspaceId })
        });

        const data = await res.json();
        if (data.url) {
            window.location.href = data.url;
        } else {
            alert(data.error || "Impossible d'accéder au portail.");
        }
    } catch (error) {
        console.error(error);
        alert("Erreur d'accès au portail de facturation.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleContactSales = () => {
    window.location.href = "mailto:sales@citedby.ai?subject=Demande%20Plan%20Agency%20Multi-Clients&body=Bonjour,%20je%20suis%20une%20agence%20et%20je%20souhaite%20gérer%20plusieurs%20projets.";
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 relative animate-in fade-in duration-500">
      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour au menu
      </button>

      <div className="text-center mb-10">
         <h1 className="text-4xl font-serif font-bold mb-4">Plans & Facturation</h1>
         <p className="text-gray-400 max-w-2xl mx-auto">Gérez votre abonnement AEO ou choisissez la puissance adaptée à votre croissance.</p>
      </div>

      {/* HIGHLIGHTED TABS NAVIGATION */}
      <div className="flex justify-center mb-12">
        <div className="inline-flex bg-white/5 p-1.5 rounded-2xl border border-white/10 relative">
          <button
            onClick={() => setActiveTab('my-plan')}
            className={`px-8 py-3 rounded-xl text-sm font-bold transition-all duration-300 flex items-center gap-2 ${
              activeTab === 'my-plan' 
                ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.3)] scale-[1.02]' 
                : 'text-gray-400 hover:text-white hover:bg-white/5'
            }`}
          >
            <ShieldCheck size={18} className={activeTab === 'my-plan' ? '' : 'opacity-50'} />
            Mon Plan Actuel
          </button>

          <div className="w-px bg-white/10 my-2 mx-1"></div>

          <button
            onClick={() => setActiveTab('pricing')}
            className={`px-8 py-3 rounded-xl text-sm font-bold transition-all duration-300 flex items-center gap-2 ${
              activeTab === 'pricing' 
                ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.3)] scale-[1.02]' 
                : 'text-gray-400 hover:text-white hover:bg-white/5'
            }`}
          >
            <LayoutList size={18} className={activeTab === 'pricing' ? '' : 'opacity-50'} />
            Comparer les offres
          </button>
        </div>
      </div>

      {/* CONTENT: MON PLAN */}
      {activeTab === 'my-plan' && (
        <div className="animate-in fade-in slide-in-from-left-4 duration-300">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-medium text-white">Mon abonnement</h2>
                <span className="text-xs text-gray-500">ID Client: {user?.id || 'GUEST'}</span>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
                {/* Card 1: Plan Status & Usage */}
                <div className="glass-panel p-8 rounded-xl border border-white/10 relative overflow-hidden">
                    {/* Background effects */}
                    <div className="absolute top-0 right-0 w-32 h-32 bg-primary/10 blur-3xl -z-10"></div>

                    {/* Plan Header */}
                    <div className="flex justify-between items-start mb-8">
                        <div className="flex items-center gap-4">
                        <div className="w-14 h-14 rounded-xl bg-gradient-to-br from-primary to-emerald-800 flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-primary/20">
                            P
                        </div>
                        <div>
                            <h3 className="font-bold text-xl text-white">Plan {user?.plan === 'free' ? 'Starter' : user?.plan === 'enterprise' ? 'Agency' : 'Pro'}</h3>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                                <span className="text-xs text-emerald-400 font-medium uppercase tracking-wide">Actif</span>
                            </div>
                        </div>
                        </div>
                        <button 
                            onClick={() => setActiveTab('pricing')}
                            className="text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-4 py-2 rounded-lg transition-colors text-gray-300"
                        >
                            Changer d'offre
                        </button>
                    </div>

                    {/* Usage Stats (Projects / Prompts) */}
                    <div className="mb-8 bg-black/20 p-5 rounded-lg border border-white/5 space-y-4">
                        <div>
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-sm text-gray-400">Projets Actifs</span>
                                <span className="text-sm font-bold text-white">
                                    {user?.plan === 'free' ? '1 / 1' : user?.plan === 'enterprise' ? '∞' : '1 / 3'}
                                </span>
                            </div>
                            <div className="h-2 bg-gray-700 rounded-full overflow-hidden">
                                <div className="h-full bg-primary rounded-full" style={{ width: user?.plan === 'free' ? '100%' : '33%' }}></div>
                            </div>
                        </div>

                        <div>
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-sm text-gray-400">Crédits de Génération</span>
                                <span className="text-sm font-bold text-white">{user?.credits} restants</span>
                            </div>
                            <div className="h-2 bg-gray-700 rounded-full overflow-hidden">
                                <div 
                                    className="h-full bg-accent rounded-full transition-all duration-500"
                                    style={{ width: `${Math.min(((user?.credits || 0) / 100) * 100, 100)}%` }}
                                ></div>
                            </div>
                        </div>

                        <p className="text-xs text-gray-500 flex items-center gap-1 pt-2">
                            <Star size={10} className="text-accent" /> Renouvellement des quotas le 01 du mois prochain
                        </p>
                    </div>

                    {/* Features List */}
                    <div className="space-y-4 mb-8">
                        <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-2">Fonctionnalités activées</p>
                        {[
                        "1 Projet (Site Web)",
                        "Monitoring Mensuel",
                        "20 Prompts par défaut",
                        "Score de Visibilité IA",
                        "Support Email Standard"
                        ].map((feat, i) => (
                        <div key={i} className="flex items-center gap-3 text-sm text-gray-300">
                            <div className="w-5 h-5 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                                <Check size={12} className="text-primary" />
                            </div>
                            {feat}
                        </div>
                        ))}
                    </div>
                </div>

                {/* Card 2: Billing Info */}
                <div className="space-y-8">
                    <div className="glass-panel p-8 rounded-xl border border-white/10 hover:border-white/20 transition-colors">
                        <h3 className="font-medium text-white mb-6 flex items-center gap-2 text-lg">
                        <CreditCard size={20} className="text-primary" />
                        Facturation & Méthodes de paiement
                        </h3>
                        <div className="space-y-5">
                        <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
                            <span className="text-gray-400">Prochaine facture</span>
                            <span className="font-medium text-lg">-</span>
                        </div>
                        <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
                            <span className="text-gray-400">Statut Stripe</span>
                            <span className="text-xs text-gray-500 italic">Via Portail</span>
                        </div>
                        </div>
                        <button 
                            onClick={handleManageSubscription}
                            disabled={isLoading}
                            className="w-full mt-6 py-2.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-sm text-gray-300 hover:text-white flex items-center justify-center gap-2 transition-colors group"
                        >
                            {isLoading ? <Loader2 size={16} className="animate-spin" /> : <CreditCard size={16} className="group-hover:text-primary transition-colors" />}
                            Gérer mon abonnement Stripe
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

      {/* CONTENT: NOS OFFRES */}
      {activeTab === 'pricing' && (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="text-center mb-10">
                  <h2 className="text-2xl font-serif font-bold mb-3">Évoluez avec vos besoins</h2>
                  <p className="text-gray-400">Des solutions adaptées de l'indépendant à l'agence marketing.</p>
              </div>

              <div className="grid md:grid-cols-3 gap-6">
                  {/* Plan Starter */}
                  <div className="glass-panel p-6 rounded-xl border border-white/10 flex flex-col hover:border-white/20 transition-all">
                      <div className="mb-4">
                          <h3 className="text-lg font-bold flex items-center gap-2"><Zap size={18} className="text-gray-400" /> Starter</h3>
                          <div className="text-3xl font-bold mt-2 font-serif">Gratuit</div>
                      </div>
                      <p className="text-sm text-gray-400 mb-6 min-h-[40px]">Pour découvrir l'AEO et monitorer un site unique.</p>

                      <div className="border-t border-white/10 pt-4 mb-6 flex-1">
                          <ul className="space-y-3">
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> 1 Projet (Site)</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> Monitoring Mensuel</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> 20 Prompts Standards</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> Score Visibilité IA</li>
                          </ul>
                      </div>

                      <button 
                        onClick={onNavigateToProjects}
                        className="w-full py-3 border border-white/10 rounded-lg bg-white/5 hover:bg-white/10 text-white transition-colors text-sm font-medium flex items-center justify-center gap-2"
                      >
                         Accéder à mes projets <ArrowRight size={14} />
                      </button>
                  </div>

                  {/* Plan Pro */}
                  <div className="glass-panel p-6 rounded-xl border border-primary/50 bg-primary/5 flex flex-col relative transform hover:-translate-y-1 transition-all duration-300 shadow-[0_0_30px_rgba(16,185,129,0.1)]">
                      <div className="absolute top-0 left-1/2 -translate-x-1/2 bg-primary text-black text-[10px] uppercase font-bold px-3 py-1 rounded-b-lg tracking-wider">Recommandé</div>
                      <div className="mb-4 mt-2">
                          <h3 className="text-lg font-bold text-primary flex items-center gap-2"><Zap size={18} /> Pro</h3>
                          <div className="text-3xl font-bold mt-2 font-serif">89€ <span className="text-sm font-normal text-gray-500 font-sans">/mois</span></div>
                      </div>
                      <p className="text-sm text-gray-300 mb-6 min-h-[40px]">Pour les PME sérieuses qui veulent dominer les réponses IA.</p>

                      <div className="border-t border-white/10 pt-4 mb-6 flex-1">
                          <ul className="space-y-3">
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> <strong>3 Projets</strong></li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Monitoring <strong>Hebdomadaire</strong></li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Exports PDF & CSV</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Moteur de Recommandations</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Générateur Packs Contenu</li>
                          </ul>
                      </div>

                      <button 
                        onClick={handleSubscribePro}
                        disabled={isLoading}
                        className="w-full py-3 bg-primary text-black font-bold rounded-lg hover:bg-primaryDark transition-colors text-sm flex items-center justify-center gap-2 shadow-lg shadow-primary/20"
                      >
                        {isLoading ? <Loader2 className="animate-spin" size={16} /> : <CreditCard size={16} />} 
                        S'abonner maintenant
                      </button>
                  </div>

