{"content":"import { NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { stripe, PLANS } from '@/lib/stripe';

export async function POST(req: Request) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const body = await req.json();
  const { workspaceId, plan } = body; 

  if (!workspaceId) return NextResponse.json({ error: 'Workspace ID required' }, { status: 400 });

  // 1. Vérifier le rôle (Owner/Admin seulement)
  const { data: membership } = await supabase
    .from('workspace_users')
    .select('role')
    .eq('workspace_id', workspaceId)
    .eq('user_id', user.id)
    .single();

  if (!membership || !['owner', 'admin'].includes(membership.role)) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
  }

  // 2. Récupérer le customer ID existant s'il y en a un
  const { data: workspace } = await supabase
    .from('workspaces')
    .select('stripe_customer_id')
    .eq('id', workspaceId)
    .single();

  let customerId = workspace?.stripe_customer_id;

  // 3. Créer le Customer Stripe si inexistant
  if (!customerId) {
    const customer = await stripe.customers.create({
      email: user.email,
      metadata: { workspaceId: workspaceId }
    });
    customerId = customer.id;
    // Mise à jour DB
    await supabase.from('workspaces').update({ stripe_customer_id: customerId }).eq('id', workspaceId);
  }

  // 4. Créer la session
  const priceId = PLANS[plan as keyof typeof PLANS];

  const session = await stripe.checkout.sessions.create({
    customer: customerId,
    line_items: [{ price: priceId, quantity: 1 }],
    mode: 'subscription',
    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing?success=true`,
    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing?canceled=true`,
    subscription_data: {
      metadata: { workspaceId: workspaceId }
    },
    metadata: { workspaceId: workspaceId }
  });

  return NextResponse.json({ url: session.url });
}"}

{"content":"import { NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { stripe } from '@/lib/stripe';

export async function POST(req: Request) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const { workspaceId } = await req.json();

  const { data: membership } = await supabase
    .from('workspace_users')
    .select('role')
    .eq('workspace_id', workspaceId)
    .eq('user_id', user.id)
    .single();

  if (!membership || !['owner', 'admin'].includes(membership.role)) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
  }

  const { data: workspace } = await supabase
    .from('workspaces')
    .select('stripe_customer_id')
    .eq('id', workspaceId)
    .single();

  if (!workspace?.stripe_customer_id) {
    return NextResponse.json({ error: 'No billing account' }, { status: 400 });
  }

  const session = await stripe.billingPortal.sessions.create({
    customer: workspace.stripe_customer_id,
    return_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing`,
  });

  return NextResponse.json({ url: session.url });
}"}

