{"content":"import { headers } from 'next/headers';
import { NextResponse } from 'next/server';
import { stripe, getPlanFromPriceId } from '@/lib/stripe';
import { createClient } from '@supabase/supabase-js';
import Stripe from 'stripe';

// Client Admin pour bypasser RLS
const supabaseAdmin = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export async function POST(req: Request) {
  const body = await req.text();
  const signature = headers().get('Stripe-Signature') as string;

  let event: Stripe.Event;

  try {
    event = stripe.webhooks.constructEvent(
      body,
      signature,
      process.env.STRIPE_WEBHOOK_SECRET!
    );
  } catch (error) {
    return new NextResponse('Webhook error', { status: 400 });
  }

  // Idempotence
  const { data: processed } = await supabaseAdmin
    .from('stripe_events_processed')
    .select('id')
    .eq('event_id', event.id)
    .single();

  if (processed) return new NextResponse('Event already processed', { status: 200 });

  const session = event.data.object as Stripe.Checkout.Session | Stripe.Subscription;

  // 1. Gestion des événements
  if (event.type === 'checkout.session.completed') {
    const checkoutSession = session as Stripe.Checkout.Session;
    const workspaceId = checkoutSession.metadata?.workspaceId;
    const subscriptionId = checkoutSession.subscription as string;

    if (workspaceId) {
      await supabaseAdmin.from('workspaces').update({
        stripe_subscription_id: subscriptionId,
        stripe_customer_id: checkoutSession.customer as string,
      }).eq('id', workspaceId);
    }
  }

  if (event.type === 'customer.subscription.created' || event.type === 'customer.subscription.updated') {
    const subscription = session as Stripe.Subscription;
    const workspaceId = subscription.metadata?.workspaceId;

    const priceId = subscription.items.data[0].price.id;
    const planName = getPlanFromPriceId(priceId);

    if (workspaceId) {
      await supabaseAdmin.from('workspaces').update({
        plan: planName,
        plan_status: subscription.status,
        current_period_end: new Date(subscription.current_period_end * 1000).toISOString(),
      }).eq('id', workspaceId);
    }
  }

  if (event.type === 'customer.subscription.deleted') {
    const subscription = session as Stripe.Subscription;
    const workspaceId = subscription.metadata?.workspaceId;

    if (workspaceId) {
      await supabaseAdmin.from('workspaces').update({
        plan: 'starter',
        plan_status: 'canceled',
        stripe_subscription_id: null
      }).eq('id', workspaceId);
    }
  }

  // 2. Enregistrer l'event
  await supabaseAdmin.from('stripe_events_processed').insert({
    event_id: event.id,
    type: event.type
  });

  return new NextResponse(null, { status: 200 });
}"}
